async function delay(ms: number): Promise<string> {
  return new Promise(resolve => {
    setTimeout(() => resolve(`Done after ${ms}ms`), ms);
  });
}

async function main() {
  const result = await delay(0);
  console.log(result);
  console.log("Async functions always return a Promise");
}

main();

function riskyOperation(shouldFail: boolean): string {
  if (shouldFail) throw new Error("Operation failed!");
  return "Success";
}

function safeRun(shouldFail: boolean): string {
  try {
    return riskyOperation(shouldFail);
  } catch (error) {
    if (error instanceof Error) {
      return `Caught: ${error.message}`;
    }
    return "Caught unknown error";
  }
}

console.log(safeRun(false));
console.log(safeRun(true));

async function fetchNumber(n: number): Promise<number> {
  return n * n;
}

async function main() {
  const [a, b, c]: [number, number, number] = await Promise.all([
    fetchNumber(2),
    fetchNumber(3),
    fetchNumber(4),
  ]);

  console.log(a);
  console.log(b);
  console.log(c);
  console.log(`Total: ${a + b + c}`);
}

main();
